onClick:
{{
  (async () => {
    try {
      // Bắt buộc phải có Mã vật liệu, Số lượng và Chọn Nhân viên
      if (!inp_MaVatLieu.text || !inp_SoLuong.text || !sel_NhanVien.selectedOptionValue) {
        showAlert("Vui lòng điền đủ Mã vật liệu, Số lượng và Nhân viên thao tác!请填写物料代码、数量和操作员 ID！", "warning");
        return;
      }

      // Chạy lệnh Xuất
      await Action_Submit_XuatKho.run();

      // Thông báo thành công
      showAlert("Xuất kho thành công出库成功!", "success");

      // Cập nhật lại các bảng dữ liệu
      await Get_LichSu_Xuat.run(); 
      await Get_Tong_Kho_Phu_Tung.run(); 

      // Xóa trắng Form
      resetWidget("Form_Xuat_Nhap", true); 

    } catch (err) {
      showAlert("❌ Lỗi: " + err.message, "error");
    }
  })()
}}
